# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 500;
    
    public Dictionary<string, int> upgrades = new Dictionary<string, int>();
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }
    
    public bool CanAfford(int price)
    {
        return currency >= price;
    }
    
    public void SpendCurrency(int amount)
    {
        if (CanAfford(amount))
        {
            currency -= amount;
        }
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
    }
    
    public int CalculateDamage()
    {
        int baseDamage = 10;
        if (upgrades.ContainsKey("DamageUpgrade"))
        {
            baseDamage += upgrades["DamageUpgrade"] * 5;
        }
        return baseDamage;
    }
    
    public int CalculateUpgradeCost(string upgradeType, int currentLevel)
    {
        if (upgradeType == "DamageUpgrade")
        {
            return 100 * (currentLevel + 1);
        }
        return 0;
    }
    
    public bool PurchaseUpgrade(string upgradeType)
    {
        int currentLevel = upgrades.ContainsKey(upgradeType) ? upgrades[upgradeType] : 0;
        int cost = CalculateUpgradeCost(upgradeType, currentLevel);
        
        if (CanAfford(cost))
        {
            SpendCurrency(cost);
            upgrades[upgradeType] = currentLevel + 1;
            return true;
        }
        return false;
    }
    
    public void HealPlayer(int amount)
    {
        health = Mathf.Min(health + amount, maxHealth);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    
    public void BuyDamageUpgrade()
    {
        if (playerStats.PurchaseUpgrade("DamageUpgrade"))
        {
            Debug.Log("Damage upgrade purchased!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }
    
    public void BuyHealthPotion()
    {
        int cost = 50;
        if (playerStats.CanAfford(cost))
        {
            playerStats.SpendCurrency(cost);
            playerStats.HealPlayer(30);
            Debug.Log("Health potion purchased!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }
    
    public void BuyMaxHealthUpgrade()
    {
        int cost = 200;
        if (playerStats.CanAfford(cost))
        {
            playerStats.SpendCurrency(cost);
            playerStats.maxHealth += 20;
            playerStats.HealPlayer(20);
            Debug.Log("Max health upgraded!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    
    public void ApplyDamageToEnemy(int damage)
    {
        playerStats.TakeDamage(damage);
    }
    
    public int GetPlayerDamage()
    {
        return playerStats.CalculateDamage();
    }
    
    public void AddCurrency(int amount)
    {
        playerStats.AddCurrency(amount);
    }
    
    public void SavePlayerStats()
    {
        PlayerPrefs.SetInt("PlayerHealth", playerStats.health);
        PlayerPrefs.SetInt("PlayerMaxHealth", playerStats.maxHealth);
        PlayerPrefs.SetInt("PlayerCurrency", playerStats.currency);
        
        foreach (var upgrade in playerStats.upgrades)
        {
            PlayerPrefs.SetInt("Upgrade_" + upgrade.Key, upgrade.Value);
        }
        
        PlayerPrefs.Save();
    }
    
    public void LoadPlayerStats()
    {
        playerStats.health = PlayerPrefs.GetInt("PlayerHealth", 100);
        playerStats.maxHealth = PlayerPrefs.GetInt("PlayerMaxHealth", 100);
        playerStats.currency = PlayerPrefs.GetInt("PlayerCurrency", 500);
        
        // Load upgrades
        playerStats.upgrades.Clear();
        for (int i = 1; i <= 10; i++)
        {
            string key = "Upgrade_DamageUpgrade";
            if (PlayerPrefs.HasKey(key))
            {
                playerStats.upgrades["DamageUpgrade"] = PlayerPrefs.GetInt(key);
                break;
            }
        }
    }
}